contracts/core/BountyManager.sol.content:
// Fixed BountyManager.sol
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "../Interfaces/IBountyManager.sol";
import "../Interfaces/IReputationSystem.sol";
import "./ThreatToken.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title BountyManager
 * @dev Manages bounties for threat intelligence analysis in the Nexus-Security platform
 * @author Nexus-Security Team
 */

// TODO: Implement all IBountyManager interface methods
contract BountyManager {
    // Enums
    enum BountyStatus {
        Active,      // Bounty is open for submissions
        InReview,    // Analysis period has ended, consensus being calculated
        Completed,   // Bounty resolved with consensus
        Cancelled,   // Bounty cancelled by creator
        Disputed     // Bounty under dispute resolution
    }

    enum ThreatVerdict {
        Pending,    // No verdict yet
        Benign,     // File/URL is safe
        Malicious,  // File/URL is a threat
        Suspicious  // File/URL requires further investigation
    }

    // Structs
    struct Bounty {
        uint256 id;
        address creator;
        string artifactHash;
        string artifactType;
        uint256 rewardAmount;
        uint256 deadline;
        string description;
        BountyStatus status;
        ThreatVerdict consensusVerdict;
        uint256 totalStaked;
        uint256 analysisCount;
        uint256 createdAt;
    }

    struct Analysis {
        uint256 bountyId;
        address analyst;
        ThreatVerdict verdict;
        uint256 confidence;
        uint256 stakeAmount;
        string analysisHash;
        uint256 submittedAt;
        bool rewarded;
    }

    // state variables
    ThreatToken public immutable threatToken;
    IReputationSystem public immutable reputationSystem;

    uint256 public bountyCounter;
    uint256 public constant MIN_STAKE_AMOUNT = 10 * 10**18;   // 10 token minimum stake
    uint256 public constant ANALYSIS_TIMEOUT = 24 hours;   // 24 hours to complete analysis
    uint256 public constant CONSENSUS_THRESHOLD = 66;   // 66% consensus required
    uint256 public constant PLATFORM_FEE_PERCENT = 5;    // 5% platfrom fee
    uint256 public constant MIN_ANALYSES_TO_RESOLVE = 5; // Synced threshold

    address public owner;
    address public feeCollector;
    bool public paused;

    // Mappings
    mapping(uint256 => Bounty) public bounties;
    mapping(uint256 => mapping(address => Analysis)) public analyses;
    mapping(uint256 => address[]) public bountyAnalysts;
    mapping(address => uint256[]) public userBounties;
    mapping(uint256 => mapping(address => uint256)) public analystSubmissionIds; // Added for rep integration

    // Events
    event BountyCreated(
        uint256 indexed bountyId,
        address indexed creator,
        string artifactHash,
        uint256 reward,
        uint256 deadline
    );

    event AnalysisSubmitted(
        uint256 indexed bountyId,
        address indexed engine,
        ThreatVerdict verdict,
        uint256 stake,
        uint256 confidence
    );

    event ConsensusReached(
        uint256 indexed bountyId,
        ThreatVerdict consensus,
        uint256 confidenceScore,
        uint256 totalAnalyses
    );

    event RewardsDistributed(
        uint256 indexed bountyId,
        address[] winners,
        uint256[] rewards,
        uint256[] stakes
    );

    // Modifiers
    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    modifier notPaused() {
        require(!paused, "Contract is paused");
        _;
    }

    modifier validBounty(uint256 bountyId) {
        require(bountyId > 0 && bountyId <= bountyCounter, "Invalid bounty ID");
        _;
    }

    modifier bountyActive(uint256 bountyId) {
        require(bounties[bountyId].status == BountyStatus.Active, "Bounty not active");
        require(block.timestamp <= bounties[bountyId].deadline, "Bounty expired");
        _;
    }

    constructor(
        address _threatToken,
        address _reputationSystem,
        address _feeCollector
    ) {
        require(_threatToken != address(0), "Invalid token address");
        require(_reputationSystem != address(0), "Invalid reputation system address");
        require(_feeCollector != address(0), "Invalid fee collector address");

        threatToken = ThreatToken(_threatToken);
        reputationSystem = IReputationSystem(_reputationSystem);
        feeCollector = _feeCollector;
        owner = msg.sender;
    }

    /**
     * @dev Create a new bounty for threat analysis
     * @param artifactHash IPFS hash of the artifact to be analyzed
     * @param artifactType Type of artifact (file, URL, etc.)
     * @param rewardAmount Amount of tokens offered as reward
     * @param deadline Deadline for analysis submission
     * @param description Description of the bounty
     */

     function createBounty(
        string memory artifactHash,
        string memory artifactType,
        uint256 rewardAmount,
        uint256 deadline,
        string memory description
     ) external notPaused returns (uint256) {
        require(bytes(artifactHash).length > 0, "Invalid artifact hash");
        require(rewardAmount > 0, "Reward must be positive");
        require(deadline > block.timestamp + 1 hours, "Deadline too soon");
        require(bytes(description).length > 0, "Description required");

        // Transfer reward tokens to contract
        require(threatToken.transferFrom(msg.sender, address(this), rewardAmount), "Token transfer failed");

        bountyCounter++;

        bounties[bountyCounter] = Bounty({
            id: bountyCounter,
            creator: msg.sender,
            artifactHash: artifactHash,
            artifactType: artifactType,
            rewardAmount: rewardAmount,
            deadline: deadline,
            description: description,
            status: BountyStatus.Active,
            consensusVerdict: ThreatVerdict.Pending,
            totalStaked: 0,
            analysisCount: 0,
            createdAt: block.timestamp
        });

        userBounties[msg.sender].push(bountyCounter);

        emit BountyCreated(
            bountyCounter, 
            msg.sender, 
            artifactHash, 
            rewardAmount, 
            deadline
        );

        return bountyCounter;
     }

     /** 
     * @dev Submit analysis for a bounty
     * @param bountyId ID of the bounty
     * @param verdict Analysis verdict (Malicious/Benign)
     * @param confidence Confidence level (0-100)
     * @param stakeAmount Amount of tokens to stake
     * @param analysisHash IPFS hash of detailed analysis
     */

     function submitAnalysis(
        uint256 bountyId,
        ThreatVerdict verdict,
        uint256 confidence,
        uint256 stakeAmount,
        string memory analysisHash
     ) external validBounty(bountyId) bountyActive(bountyId) notPaused {
        require(verdict != ThreatVerdict.Pending, "Invalid verdict");
        require(confidence > 0 && confidence <= 100, "Invalid confidence");
        require(stakeAmount >= MIN_STAKE_AMOUNT, "Insufficient stake");
        require(bytes(analysisHash).length > 0, "Analysis hash required");
        require(analyses[bountyId][msg.sender].analyst == address(0), "Already submitted");

        // Check reputation requirements
        require(
            reputationSystem.getReputation(msg.sender) >= reputationSystem.getMinimumReputation(),
            "Insufficient reputation"
        );

        // Transfer stake to contract
        require(
            threatToken.transferFrom(msg.sender, address(this), stakeAmount),
            "Stake transfer failed"
        );

        analyses[bountyId][msg.sender] = Analysis({
            bountyId: bountyId,
            analyst: msg.sender,
            verdict: verdict,
            confidence: confidence,
            stakeAmount: stakeAmount,
            analysisHash: analysisHash,
            submittedAt: block.timestamp,
            rewarded: false
        });

        bountyAnalysts[bountyId].push(msg.sender);
        bounties[bountyId].totalStaked += stakeAmount;
        bounties[bountyId].analysisCount++;

        // TODO: Record submission in reputation system
        // uint256 submissionId = reputationSystem.recordSubmission(
        //     msg.sender,
        //     bountyId,
        //     (verdict == ThreatVerdict.Malicious),
        //     stakeAmount,
        //     confidence
        // );
        // analystSubmissionIds[bountyId][msg.sender] = submissionId;

        emit AnalysisSubmitted(
            bountyId,
            msg.sender,
            verdict,
            stakeAmount,
            confidence
        );

        // Check if we can resolve the bounty
        _checkAndResolveBounty(bountyId);
    }

    /**
     * @dev Resolve a bounty by determining consensus and distributing rewards
     * @param bountyId ID of the bounty to resolve
     */
    function resolveBounty(uint256 bountyId) 
        external 
        validBounty(bountyId) 
        notPaused 
    {
        Bounty storage bounty = bounties[bountyId];
        require(bounty.status == BountyStatus.Active, "Bounty not active");
        require(
            block.timestamp > bounty.deadline || bounty.analysisCount >= MIN_ANALYSES_TO_RESOLVE,
            "Cannot resolve yet"
        );

        _resolveBountyInternal(bountyId);
    }

    /**
     * @dev Internal function to check if bounty can be resolved automatically
     */
    function _checkAndResolveBounty(uint256 bountyId) internal {
        Bounty storage bounty = bounties[bountyId];

        // Auto-resolve if we have enough analyses or deadline passed
        if (bounty.analysisCount >= MIN_ANALYSES_TO_RESOLVE * 2 || block.timestamp > bounty.deadline) { // Adjusted to 10 for auto
            _resolveBountyInternal(bountyId);
        }
    }

    /**
     * @dev Internal function to resolve bounty and distribute rewards
     */
    function _resolveBountyInternal(uint256 bountyId) internal {
        Bounty storage bounty = bounties[bountyId];
        address[] storage analysts = bountyAnalysts[bountyId];

        if (analysts.length == 0) {
            // No analyses submitted, refund creator
            bounty.status = BountyStatus.Cancelled;
            require(
                threatToken.transfer(bounty.creator, bounty.rewardAmount),
                "Refund failed"
            );
            return;
        }

        // Calculate consensus
        (ThreatVerdict consensus, uint256 consensusCount) = _calculateConsensus(bountyId);

        bounty.consensusVerdict = consensus;
        bounty.status = BountyStatus.Completed;

        // Update reputation for all analysts based on their analysis accuracy
        for (uint256 i = 0; i < analysts.length; i++) {
            address analyst = analysts[i];
            Analysis storage analysis = analyses[bountyId][analyst];

            // Check if analyst's verdict matches consensus
            bool wasCorrect = (analysis.verdict == consensus);

            // Update reputation in reputation system
            reputationSystem.updateReputationForAnalysis(
                analyst,
                bountyId,
                wasCorrect,
                analysis.stakeAmount
            );
        }

        // Distribute rewards and slash stakes
        _distributeRewards(bountyId, consensus, consensusCount);

        // Calculate confidence score (percentage of consensus)
        uint256 totalAnalyses = bountyAnalysts[bountyId].length;
        uint256 confidenceScore = totalAnalyses > 0 ? (consensusCount * 10000) / totalAnalyses : 0; // basis points

        emit ConsensusReached(bountyId, consensus, confidenceScore, totalAnalyses);
    }

    /**
     * @dev Calculate consensus from all analyses
     */
    function _calculateConsensus(uint256 bountyId) 
        internal 
        view 
        returns (ThreatVerdict consensus, uint256 consensusCount) 
    {
        address[] storage analysts = bountyAnalysts[bountyId];
        uint256 maliciousCount = 0;
        uint256 benignCount = 0;
        uint256 totalWeight = 0;

        for (uint256 i = 0; i < analysts.length; i++) {
            Analysis storage analysis = analyses[bountyId][analysts[i]];
            uint256 weight = analysis.stakeAmount * analysis.confidence / 100;
            totalWeight += weight;

            if (analysis.verdict == ThreatVerdict.Malicious) {
                maliciousCount += weight;
            } else if (analysis.verdict == ThreatVerdict.Benign) {
                benignCount += weight;
            }
        }

        if (totalWeight == 0) {
            return (ThreatVerdict.Pending, 0);
        }

        uint256 maliciousPercent = (maliciousCount * 100) / totalWeight;
        uint256 benignPercent = (benignCount * 100) / totalWeight;

        if (maliciousPercent >= CONSENSUS_THRESHOLD) {
            consensus = ThreatVerdict.Malicious;
            consensusCount = _countCorrectAnalyses(bountyId, ThreatVerdict.Malicious);
        } else if (benignPercent >= CONSENSUS_THRESHOLD) {
            consensus = ThreatVerdict.Benign;
            consensusCount = _countCorrectAnalyses(bountyId, ThreatVerdict.Benign);
        } else {
            consensus = ThreatVerdict.Pending; // No clear consensus
            consensusCount = 0;
        }
    }

    /**
     * @dev Count analyses that match the consensus
     */
    function _countCorrectAnalyses(uint256 bountyId, ThreatVerdict consensus) 
        internal 
        view 
        returns (uint256 count) 
    {
        address[] storage analysts = bountyAnalysts[bountyId];
        for (uint256 i = 0; i < analysts.length; i++) {
            if (analyses[bountyId][analysts[i]].verdict == consensus) {
                count++;
            }
        }
    }

    /**
     * @dev Distribute rewards to correct analysts and slash incorrect ones
     */
    function _distributeRewards(
        uint256 bountyId, 
        ThreatVerdict consensus, 
        uint256 winnerCount
    ) internal {
        Bounty storage bounty = bounties[bountyId];
        address[] storage analysts = bountyAnalysts[bountyId];

        uint256 totalRewardPool = bounty.rewardAmount;
        uint256 platformFee = (totalRewardPool * PLATFORM_FEE_PERCENT) / 100;
        uint256 rewardPool = totalRewardPool - platformFee;

        if (consensus == ThreatVerdict.Pending || winnerCount == 0) {
            // No consensus reached, refund creator minus platform fee, return stakes
            uint256 refundAmount = totalRewardPool - platformFee;

            require(threatToken.transfer(feeCollector, platformFee), "Fee transfer failed");
            require(threatToken.transfer(bounty.creator, refundAmount), "Refund failed");

            // Return stakes
            for (uint256 i = 0; i < analysts.length; i++) {
                address analyst = analysts[i];
                Analysis storage analysis = analyses[bountyId][analyst];
                require(threatToken.transfer(analyst, analysis.stakeAmount), "Stake return failed");
            }
            return;
        }

        // Add slashed stakes to reward pool
        uint256 slashedAmount = _processSlashing(bountyId, consensus);
        rewardPool += slashedAmount;

        // Distribute rewards to winners
        uint256 individualReward = rewardPool / winnerCount;

        // Collect winners for event emission
        address[] memory winners = new address[](winnerCount);
        uint256[] memory rewards = new uint256[](winnerCount);
        uint256[] memory stakes = new uint256[](winnerCount);
        uint256 winnerIndex = 0;

        for (uint256 i = 0; i < analysts.length; i++) {
            address analyst = analysts[i];
            Analysis storage analysis = analyses[bountyId][analyst];

            if (analysis.verdict == consensus && !analysis.rewarded) {
                analysis.rewarded = true;

                // Return stake + reward
                uint256 totalPayout = analysis.stakeAmount + individualReward;
                require(threatToken.transfer(analyst, totalPayout), "Reward transfer failed");

                // Collect for event
                winners[winnerIndex] = analyst;
                rewards[winnerIndex] = individualReward;
                stakes[winnerIndex] = analysis.stakeAmount;
                winnerIndex++;
            }
        }

        // Transfer platform fee
        require(threatToken.transfer(feeCollector, platformFee), "Fee transfer failed");

        // Emit rewards distributed event
        emit RewardsDistributed(bountyId, winners, rewards, stakes);
    }

    /**
     * @dev Process slashing for incorrect analyses
     */
    function _processSlashing(uint256 bountyId, ThreatVerdict consensus)
        internal
        returns (uint256 totalSlashed)
    {
        address[] storage analysts = bountyAnalysts[bountyId];

        for (uint256 i = 0; i < analysts.length; i++) {
            address analyst = analysts[i];
            Analysis storage analysis = analyses[bountyId][analyst];

            if (analysis.verdict != consensus) {
                totalSlashed += analysis.stakeAmount;
                // Stakes are slashed (added to reward pool)
            }
        }
    }

    // View functions
    function getBounty(uint256 bountyId) 
        external 
        view 
        validBounty(bountyId) 
        returns (Bounty memory) 
    {
        return bounties[bountyId];
    }

    function getAnalysis(uint256 bountyId, address analyst) 
        external 
        view 
        validBounty(bountyId) 
        returns (Analysis memory) 
    {
        return analyses[bountyId][analyst];
    }

    function getBountyAnalysts(uint256 bountyId) 
        external 
        view 
        validBounty(bountyId) 
        returns (address[] memory) 
    {
        return bountyAnalysts[bountyId];
    }

    function getUserBounties(address user) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return userBounties[user];
    }

    function getTotalBounties() external view returns (uint256) {
        return bountyCounter;
    }

    // Admin functions
    function pause() external onlyOwner {
        paused = true;
    }

    function unpause() external onlyOwner {
        paused = false;
    }

    function setFeeCollector(address _feeCollector) external onlyOwner {
        require(_feeCollector != address(0), "Invalid fee collector");
        feeCollector = _feeCollector;
    }

    function emergencyWithdraw(address token, uint256 amount) external onlyOwner {
        require(paused, "Contract must be paused");
        if (token == address(0)) {
            payable(owner).transfer(amount);
        } else {
            IERC20(token).transfer(owner, amount);
        }
    }
}

contracts/core/ThreatToken.sol.content:
// SPDX-License-Identifier: MIT
// Fixed ThreatToken.sol
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Pausable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title ThreatToken
 * @dev ERC20 token for Nexus-Security threat intelligence marketplace
 * 
 * Features:
 * - Standard ERC20 functionality
 * - Burnable tokens for deflationary mechanics
 * - Pausable for emergency stops
 * - Role-based access control
 * - Staking mechanism for analysis engines
 * - Reward distribution for accurate threat detection
 * - Anti-manipulation safeguards
 */

contract ThreatToken is ERC20, ERC20Burnable, ERC20Pausable, AccessControl, ReentrancyGuard {
    // Roles
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant BOUNTY_MANAGER_ROLE = keccak256("BOUNTY_MANAGER_ROLE");
    bytes32 public constant REPUTATION_MANAGER_ROLE = keccak256("REPUTATION_MANAGER_ROLE");

    // Token Economics
    uint256 public constant MAX_SUPPLY = 1_000_000_000 * 10**18; // 1 billion tokens
    uint256 public constant INITIAL_SUPPLY = 100_000_000 * 10**18; // 100 million tokens

    // Staking Configuration
    uint256 public constant MIN_STAKE_AMOUNT = 100 * 10**18; // Minimum 100 tokens to stake
    uint256 public constant STAKE_LOCK_PERIOD = 24 hours; // 24 hours lock period
    uint256 public constant SLASH_PERCENTAGE = 10; // 10% slashing for incorrect analysis

    // Reward Configuration
    uint256 public constant BASE_REWARD_RATE = 5; // 5% base reward for correct analysis
    uint256 public constant BONUS_MULTIPLIER = 150; // 150% multiplier for first correct analysis

    // Structs
    struct Stake {
        uint256 amount;
        uint256 lockTime;
        bool active;
        address engine;
        bytes32 analysisId;
    }

    struct RewardPool {
        uint256 totalPool;
        uint256 distributed;
        mapping(address => uint256) engineRewards;
        bool finalized;
    }

    // State Variables
    mapping(address => Stake[]) public engineStakes;
    mapping(bytes32 => RewardPool) public analysisRewards;
    mapping(address => uint256) public totalStaked;
    mapping(address => uint256) public engineReputation;
    mapping(address => bool) public authorizedEngines;
    uint256 public globalActiveStakes; // Added for emergency recover tracking

    // Events
    event Staked(address indexed engine, uint256 amount, bytes32 indexed analysisId, uint256 stakeIndex);
    event Unstaked(address indexed engine, uint256 amount, bytes32 indexed analysisId, uint256 stakeIndex);
    event Slashed(address indexed engine, uint256 amount, bytes32 indexed analysisId, uint256 stakeIndex);
    event RewardDistributed(address indexed engine, uint256 amount, bytes32 indexed analysisId);
    event EngineAuthorized(address indexed engine, bool authorized);
    event ReputationUpdated(address indexed engine, uint256 newReputation);
    event TokensMinted(address indexed to, uint256 amount); // Added for mint transparency

    constructor(address admin) ERC20("ThreatToken", "THREAT") {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(PAUSER_ROLE, admin);
        _grantRole(MINTER_ROLE, admin);
        _grantRole(BOUNTY_MANAGER_ROLE, admin);
        _grantRole(REPUTATION_MANAGER_ROLE, admin);

        // Mint initial supply to admin
        _mint(admin, INITIAL_SUPPLY);
    }

    /**
     * @dev Mint new tokens (up to max supply)
     * @param to Address to mint tokens to
     * @param amount Amount of tokens to mint
     */
    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        require(totalSupply() + amount <= MAX_SUPPLY, "Exceeds max supply");
        _mint(to, amount);
        emit TokensMinted(to, amount);
    }

    /**
     * @dev Pause all token transfers
     */
    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    /**
     * @dev Unpause all token transfers
     */
    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    /**
     * @dev Authorize or deauthorize an analysis engine
     * @param engine Address of the engine
     * @param authorized Whether the engine is authorized
     */
    function setEngineAuthorization(address engine, bool authorized) 
        external 
        onlyRole(REPUTATION_MANAGER_ROLE) 
    {
        authorizedEngines[engine] = authorized;
        emit EngineAuthorized(engine, authorized);
    }

    /**
     * @dev Stake tokens for analysis participation
     * @param amount Amount of tokens to stake
     * @param analysisId Unique identifier for the analysis
     */
    function stakeForAnalysis(uint256 amount, bytes32 analysisId) 
        external 
        nonReentrant 
        whenNotPaused 
    {
        require(authorizedEngines[msg.sender], "Engine not authorized");
        require(amount >= MIN_STAKE_AMOUNT, "Amount below minimum stake");
        require(balanceOf(msg.sender) >= amount, "Insufficient balance");

        // Transfer tokens to contract
        _transfer(msg.sender, address(this), amount);

        // Create stake record
        Stake memory newStake = Stake({
            amount: amount,
            lockTime: block.timestamp + STAKE_LOCK_PERIOD,
            active: true,
            engine: msg.sender,
            analysisId: analysisId
        });

        engineStakes[msg.sender].push(newStake);
        totalStaked[msg.sender] += amount;
        globalActiveStakes += amount; // Added

        uint256 stakeIndex = engineStakes[msg.sender].length - 1;
        emit Staked(msg.sender, amount, analysisId, stakeIndex);
    }

    /**
     * @dev Unstake tokens after lock period (if analysis allows)
     * @param stakeIndex Index of the stake to unstake
     */
    function unstake(uint256 stakeIndex) external nonReentrant whenNotPaused {
        require(stakeIndex < engineStakes[msg.sender].length, "Invalid stake index");

        Stake storage stake = engineStakes[msg.sender][stakeIndex];
        require(stake.active, "Stake not active");
        require(stake.engine == msg.sender, "Not stake owner");
        require(block.timestamp >= stake.lockTime, "Stake still locked");
        require(analysisRewards[stake.analysisId].finalized, "Analysis not finalized");

        uint256 amount = stake.amount;
        stake.active = false;
        totalStaked[msg.sender] -= amount;
        globalActiveStakes -= amount; // Added

        // Return tokens to engine
        _transfer(address(this), msg.sender, amount);

        emit Unstaked(msg.sender, amount, stake.analysisId, stakeIndex);
    }

    /**
     * @dev Slash tokens from incorrect analysis
     * @param engine Address of the engine to slash
     * @param stakeIndex Index of the stake to slash
     */
    function slashStake(address engine, uint256 stakeIndex) 
        external 
        onlyRole(BOUNTY_MANAGER_ROLE) 
        nonReentrant 
    {
        require(stakeIndex < engineStakes[engine].length, "Invalid stake index");

        Stake storage stake = engineStakes[engine][stakeIndex];
        require(stake.active, "Stake not active");

        uint256 slashAmount = (stake.amount * SLASH_PERCENTAGE) / 100;
        uint256 remainingAmount = stake.amount - slashAmount;

        stake.amount = remainingAmount;
        totalStaked[engine] -= slashAmount;
        globalActiveStakes -= slashAmount; // Added

        // Burn slashed tokens (deflationary mechanism)
        _burn(address(this), slashAmount);

        // Update reputation
        if (engineReputation[engine] > slashAmount) {
            engineReputation[engine] -= slashAmount;
        } else {
            engineReputation[engine] = 0;
        }

        emit Slashed(engine, slashAmount, stake.analysisId, stakeIndex);
        emit ReputationUpdated(engine, engineReputation[engine]);
    }

    /**
     * @dev Distribute rewards for correct analysis
     * @param analysisId Unique identifier for the analysis
     * @param correctEngines Array of engines that provided correct analysis
     * @param isFirstCorrect Array indicating which engines were first to be correct
     */
    function distributeRewards(
        bytes32 analysisId,
        address[] calldata correctEngines,
        bool[] calldata isFirstCorrect
    ) external onlyRole(BOUNTY_MANAGER_ROLE) nonReentrant {
        require(correctEngines.length == isFirstCorrect.length, "Array length mismatch");
        require(!analysisRewards[analysisId].finalized, "Rewards already distributed");

        RewardPool storage rewardPool = analysisRewards[analysisId];
        uint256 totalRewardsToMint = 0;

        // First pass: Calculate total to mint
        for (uint256 i = 0; i < correctEngines.length; i++) {
            address engine = correctEngines[i];
            uint256 baseReward = _calculateBaseReward(engine, analysisId);
            uint256 finalReward = baseReward;

            if (isFirstCorrect[i]) {
                finalReward = (baseReward * BONUS_MULTIPLIER) / 100;
            }

            rewardPool.engineRewards[engine] = finalReward;
            totalRewardsToMint += finalReward;
        }

        // Check total mint against max supply
        require(totalSupply() + totalRewardsToMint <= MAX_SUPPLY, "Exceeds max supply");

        // Second pass: Mint and distribute
        for (uint256 i = 0; i < correctEngines.length; i++) {
            address engine = correctEngines[i];
            uint256 finalReward = rewardPool.engineRewards[engine];

            // Update reputation
            engineReputation[engine] += finalReward;

            // Mint and transfer rewards
            _mint(engine, finalReward);
            emit RewardDistributed(engine, finalReward, analysisId);
            emit ReputationUpdated(engine, engineReputation[engine]);
        }

        rewardPool.totalPool = totalRewardsToMint;
        rewardPool.distributed = totalRewardsToMint;
        rewardPool.finalized = true;
    }

    /**
     * @dev Calculate base reward for an engine based on stake and reputation
     * @param engine Address of the engine
     * @param analysisId Analysis identifier
     * @return Base reward amount
     */
    function _calculateBaseReward(address engine, bytes32 analysisId) 
        internal 
        view 
        returns (uint256) 
    {
        uint256 stakedAmount = _getStakedAmountForAnalysis(engine, analysisId);
        uint256 reputationBonus = engineReputation[engine] / 1000; // 0.1% bonus per 1000 reputation

        uint256 baseReward = (stakedAmount * BASE_REWARD_RATE) / 100;
        uint256 bonusReward = (baseReward * reputationBonus) / 100;

        return baseReward + bonusReward;
    }

    /**
     * @dev Get staked amount for a specific analysis
     * @param engine Address of the engine
     * @param analysisId Analysis identifier
     * @return Total staked amount
     */
    function _getStakedAmountForAnalysis(address engine, bytes32 analysisId) 
        internal 
        view 
        returns (uint256) 
    {
        uint256 totalAmount = 0;
        Stake[] storage stakes = engineStakes[engine];

        for (uint256 i = 0; i < stakes.length; i++) {
            if (stakes[i].analysisId == analysisId && stakes[i].active) {
                totalAmount += stakes[i].amount;
            }
        }

        return totalAmount;
    }

    /**
     * @dev Get engine's stake information
     * @param engine Address of the engine
     * @return Array of active stake amounts and their analysis IDs
     */
    function getEngineStakes(address engine) 
        external 
        view 
        returns (Stake[] memory) 
    {
        return engineStakes[engine];
    }

    /**
     * @dev Get reward information for an analysis
     * @param analysisId Analysis identifier
     * @param engine Engine address
     * @return Reward amount for the engine
     */
    function getAnalysisReward(bytes32 analysisId, address engine) 
        external 
        view 
        returns (uint256) 
    {
        return analysisRewards[analysisId].engineRewards[engine];
    }

    /**
     * @dev Emergency function to recover stuck tokens
     * @param token Address of token to recover
     * @param amount Amount to recover
     */
    function emergencyRecover(address token, uint256 amount) 
        external 
        onlyRole(DEFAULT_ADMIN_ROLE) 
    {
        if (token == address(this)) {
            // Only recover excess tokens not part of active stakes
            uint256 contractBalance = balanceOf(address(this));
            require(amount <= contractBalance - globalActiveStakes, "Cannot recover staked tokens");
        }

        if (token == address(0)) {
            payable(msg.sender).transfer(amount);
        } else {
            IERC20(token).transfer(msg.sender, amount);
        }
    }

    // Override functions for pausable functionality (OpenZeppelin v5)
    function _update(
        address from,
        address to,
        uint256 amount
    ) internal override(ERC20, ERC20Pausable) {
        super._update(from, to, amount);
    }
}

contracts/Interfaces/IBountyManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title IBountyManager
 * @dev Interface for the Nexus-Security Bounty Manager contract
 * @notice Defines the core functionality for managing threat analysis bounties
 */
interface IBountyManager {
    // ============ ENUMS ============

    /**
     * @dev Enumeration of possible bounty states
     */
    enum BountyStatus {
        Active,      // Bounty is open for submissions
        InReview,    // Analysis period has ended, consensus being calculated
        Completed,   // Bounty resolved with consensus
        Cancelled,   // Bounty cancelled by creator
        Disputed     // Bounty under dispute resolution
    }

    /**
     * @dev Enumeration of threat verdicts
     */
    enum ThreatVerdict {
        Pending,    // No verdict yet
        Benign,     // File/URL is safe
        Malicious,  // File/URL is a threat
        Suspicious  // File/URL requires further investigation
    }

    // ============ STRUCTS ============

    /**
     * @dev Structure representing a bounty
     */
    struct Bounty {
        uint256 id;                    // Unique bounty identifier
        address creator;               // Address that created the bounty
        string artifactHash;           // Hash of the artifact being analyzed
        string artifactType;           // Type: "file", "url", "hash", etc.
        uint256 rewardAmount;          // Total reward amount in tokens
        uint256 deadline;              // Timestamp when analysis period ends
        string description;            // Description of the bounty
        BountyStatus status;           // Current status of the bounty
        ThreatVerdict consensusVerdict;// Final consensus verdict
        uint256 totalStaked;           // Total tokens staked
        uint256 analysisCount;         // Number of analyses submitted
        uint256 createdAt;             // Timestamp when bounty was created
    }

    /**
     * @dev Structure representing an analysis submission
     */
    struct Analysis {
        uint256 bountyId;              // ID of the associated bounty
        address analyst;               // Address of the analyzing engine
        ThreatVerdict verdict;         // Engine's verdict
        uint256 confidence;            // Engine's confidence (0-100)
        uint256 stakeAmount;           // Amount staked by engine
        string analysisHash;           // IPFS hash or analysis details
        uint256 submittedAt;           // Timestamp of submission
        bool rewarded;                 // Whether engine has been rewarded
    }

    // ============ EVENTS ============

    /**
     * @dev Emitted when a new bounty is created
     */
    event BountyCreated(
        uint256 indexed bountyId,
        address indexed creator,
        string targetHash,
        uint256 reward,
        uint256 deadline
    );

    /**
     * @dev Emitted when an analysis is submitted
     */
    event AnalysisSubmitted(
        uint256 indexed bountyId,
        address indexed engine,
        ThreatVerdict verdict,
        uint256 stake,
        uint256 confidence
    );

    /**
     * @dev Emitted when a bounty reaches consensus
     */
    event ConsensusReached(
        uint256 indexed bountyId,
        ThreatVerdict consensus,
        uint256 confidenceScore,
        uint256 totalAnalyses
    );

    /**
     * @dev Emitted when rewards are distributed
     */
    event RewardsDistributed(
        uint256 indexed bountyId,
        address[] winners,
        uint256[] rewards,
        uint256[] stakes
    );

    /**
     * @dev Emitted when a bounty is cancelled
     */
    event BountyCancelled(
        uint256 indexed bountyId,
        address indexed creator,
        string reason
    );

    /**
     * @dev Emitted when minimum stake is updated
     */
    event MinimumStakeUpdated(uint256 oldStake, uint256 newStake);

    // ============ BOUNTY MANAGEMENT FUNCTIONS ============

    /**
     * @dev Creates a new threat analysis bounty
     * @param artifactHash Hash or identifier of the artifact to analyze
     * @param artifactType Type of artifact ("file", "url", "domain", etc.)
     * @param rewardAmount Reward amount in tokens
     * @param deadline Timestamp when analysis period ends
     * @param description Description of the bounty
     * @return bountyId The ID of the created bounty
     */
    function createBounty(
        string calldata artifactHash,
        string calldata artifactType,
        uint256 rewardAmount,
        uint256 deadline,
        string calldata description
    ) external returns (uint256 bountyId);

    /**
     * @dev Submits an analysis for a bounty
     * @param bountyId ID of the bounty to analyze
     * @param verdict The engine's verdict on the threat
     * @param confidence Confidence level (0-100)
     * @param stakeAmount Amount of tokens to stake
     * @param analysisHash IPFS hash or analysis details
     */
    function submitAnalysis(
        uint256 bountyId,
        ThreatVerdict verdict,
        uint256 confidence,
        uint256 stakeAmount,
        string calldata analysisHash
    ) external;

    /**
     * @dev Resolves a bounty by calculating consensus and distributing rewards
     * @param bountyId ID of the bounty to resolve
     */
    function resolveBounty(uint256 bountyId) external;

    /**
     * @dev Cancels a bounty (only by creator before deadline)
     * @param bountyId ID of the bounty to cancel
     * @param reason Reason for cancellation
     */
    function cancelBounty(uint256 bountyId, string calldata reason) external;

    // ============ STAKING AND REWARDS ============

    /**
     * @dev Allows engines to withdraw their stakes from completed bounties
     * @param bountyId ID of the bounty to withdraw from
     */
    function withdrawStake(uint256 bountyId) external;

    /**
     * @dev Claims rewards for accurate analyses
     * @param bountyIds Array of bounty IDs to claim rewards from
     */
    function claimRewards(uint256[] calldata bountyIds) external;

    /**
     * @dev Emergency function to withdraw unclaimed rewards after timeout
     * @param bountyId ID of the bounty
     */
    function emergencyWithdraw(uint256 bountyId) external;

    // ============ VIEW FUNCTIONS ============

    /**
     * @dev Gets bounty information
     * @param bountyId ID of the bounty
     * @return id Bounty ID
     * @return creator Creator address
     * @return targetHash Hash of target
     * @return targetType Type of target
     * @return reward Reward amount
     * @return minimumStake Minimum stake required
     * @return deadline Analysis deadline
     * @return createdAt Creation timestamp
     * @return status Bounty status
     * @return consensus Consensus verdict
     * @return confidenceScore Confidence score
     * @return totalAnalyses Total number of analyses
     */
    function getBounty(uint256 bountyId) external view returns (
        uint256 id,
        address creator,
        string memory targetHash,
        string memory targetType,
        uint256 reward,
        uint256 minimumStake,
        uint256 deadline,
        uint256 createdAt,
        BountyStatus status,
        ThreatVerdict consensus,
        uint256 confidenceScore,
        uint256 totalAnalyses
    );

    /**
     * @dev Gets analysis information
     * @param bountyId ID of the bounty
     * @param engine Address of the analyzing engine
     * @return verdict Analysis verdict
     * @return stake Stake amount
     * @return confidence Confidence level
     * @return analysisData Analysis data hash
     * @return submittedAt Submission timestamp
     * @return isRewarded Whether rewarded
     */
    function getAnalysis(uint256 bountyId, address engine) external view returns (
        ThreatVerdict verdict,
        uint256 stake,
        uint256 confidence,
        string memory analysisData,
        uint256 submittedAt,
        bool isRewarded
    );

    /**
     * @dev Gets all analyses for a bounty
     * @param bountyId ID of the bounty
     * @return engines Array of engine addresses
     * @return verdicts Array of verdicts
     * @return stakes Array of stakes
     * @return confidences Array of confidence scores
     */
    function getBountyAnalyses(uint256 bountyId) external view returns (
        address[] memory engines,
        ThreatVerdict[] memory verdicts,
        uint256[] memory stakes,
        uint256[] memory confidences
    );

    /**
     * @dev Gets active bounties count
     * @return Number of active bounties
     */
    function getActiveBountiesCount() external view returns (uint256);

    /**
     * @dev Gets bounties created by a specific address
     * @param creator Address of the bounty creator
     * @return Array of bounty IDs
     */
    function getBountiesByCreator(address creator) external view returns (uint256[] memory);

    /**
     * @dev Gets bounties analyzed by a specific engine
     * @param engine Address of the analyzing engine
     * @return Array of bounty IDs
     */
    function getBountiesByEngine(address engine) external view returns (uint256[] memory);

    /**
     * @dev Checks if an engine has analyzed a specific bounty
     * @param bountyId ID of the bounty
     * @param engine Address of the engine
     * @return Whether the engine has submitted an analysis
     */
    function hasEngineAnalyzed(uint256 bountyId, address engine) external view returns (bool);

    /**
     * @dev Gets the current minimum stake requirement
     * @return Minimum stake in wei
     */
    function getMinimumStake() external view returns (uint256);

    /**
     * @dev Gets total rewards available for claiming by an engine
     * @param engine Address of the engine
     * @return Total claimable rewards in wei
     */
    function getPendingRewards(address engine) external view returns (uint256);

    // ============ ADMIN FUNCTIONS ============

    /**
     * @dev Updates the minimum stake requirement (admin only)
     * @param newMinimumStake New minimum stake amount
     */
    function setMinimumStake(uint256 newMinimumStake) external;

    /**
     * @dev Pauses the contract (admin only)
     */
    function pause() external;

    /**
     * @dev Unpauses the contract (admin only)
     */
    function unpause() external;

    /**
     * @dev Updates the reputation system contract address (admin only)
     * @param newReputationSystem Address of the new reputation system
     */
    function setReputationSystem(address newReputationSystem) external;
}

contracts/Interfaces/IReputationSystem.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title IReputationSystem
 * @dev Interface for the Nexus-Security reputation system
 * @notice Manages reputation scores for security analysts and automated engines
 */

 interface IReputationSystem {
    // ============ Events ============

    /**
     * @notice Emitted when an engine is registered
     * @param engineAddress The address of the registered engine
     * @param engineType Type of engine (0: Human, 1: Automated)
     * @param initialReputation Initial reputation score
     */
    event EngineRegistered(
        address indexed engineAddress,
        uint8 engineType,
        uint256 initialReputation
    );

    /**
     * @notice Emitted when reputation is updated
     * @param engineAddress The engine whose reputation changed
     * @param oldReputation Previous reputation score
     * @param newReputation New reputation score
     * @param reason Reason for reputation change
     */
    event ReputationUpdated(
        address indexed engineAddress,
        uint256 oldReputation,
        uint256 newReputation,
        string reason
    );

    /**
     * @notice Emitted when an engine is penalized
     * @param engineAddress The penalized engine
     * @param penaltyAmount Amount of reputation lost
     * @param reason Reason for penalty
     */
    event EnginePenalized(
        address indexed engineAddress,
        uint256 penaltyAmount,
        string reason
    );

    /**
     * @notice Emitted when an engine is rewarded
     * @param engineAddress The rewarded engine
     * @param rewardAmount Amount of reputation gained
     * @param bountyId Associated bounty ID
     */
    event EngineRewarded(
        address indexed engineAddress,
        uint256 rewardAmount,
        uint256 indexed bountyId
    );

    /**
     * @notice Emitted when reputation decay is applied
     * @param engineAddress The engine affected by decay
     * @param decayAmount Amount of reputation decayed
     */
    event ReputationDecayed(
        address indexed engineAddress,
        uint256 decayAmount
    );

    // ============ Structs ============

    /**
     * @notice Engine information structure
     * @param isRegistered Whether the engine is registered
     * @param engineType Type of engine (0: Human, 1: Automated)
     * @param reputation Current reputation score
     * @param totalAnalyses Total number of analyses performed
     * @param correctAnalyses Number of correct analyses
     * @param lastActivityTimestamp Timestamp of last activity
     * @param registrationTimestamp When the engine was registered
     * @param isActive Whether the engine is currently active
     */
    struct EngineInfo {
        bool isRegistered;
        uint8 engineType;
        uint256 reputation;
        uint256 totalAnalyses;
        uint256 correctAnalyses;
        uint256 lastActivityTimestamp;
        uint256 registrationTimestamp;
        bool isActive;
    }

    /**
     * @notice Reputation change record
     * @param timestamp When the change occurred
     * @param oldReputation Previous reputation
     * @param newReputation New reputation
     * @param changeType Type of change (0: Reward, 1: Penalty, 2: Decay)
     * @param bountyId Associated bounty (0 if not applicable)
     */
    struct ReputationRecord {
        uint256 timestamp;
        uint256 oldReputation;
        uint256 newReputation;
        uint8 changeType;
        uint256 bountyId;
    }

    // ============ Engine Management ============

    /**
     * @notice Register a new engine in the reputation system
     * @param engineAddress Address of the engine to register
     * @param engineType Type of engine (0: Human, 1: Automated)
     * @return success Whether registration was successful
     */
    function registerEngine(
        address engineAddress,
        uint8 engineType
    ) external returns (bool success);

    /**
     * @notice Deactivate an engine
     * @param engineAddress Address of the engine to deactivate
     * @return success Whether deactivation was successful
     */
    function deactivateEngine(
        address engineAddress
    ) external returns (bool success);

    /**
     * @notice Reactivate a previously deactivated engine
     * @param engineAddress Address of the engine to reactivate
     * @return success Whether reactivation was successful
     */
    function reactivateEngine(
        address engineAddress
    ) external returns (bool success);

    // ============ Reputation Updates ============

    /**
     * @notice Update engine reputation based on analysis accuracy
     * @param engineAddress Address of the engine
     * @param bountyId ID of the bounty being analyzed
     * @param wasCorrect Whether the engine's analysis was correct
     * @param stakeAmount Amount staked by the engine
     * @return newReputation Updated reputation score
     */
    function updateReputationForAnalysis(
        address engineAddress,
        uint256 bountyId,
        bool wasCorrect,
        uint256 stakeAmount
    ) external returns (uint256 newReputation);

    /**
     * @notice Apply penalty to an engine for malicious behavior
     * @param engineAddress Address of the engine to penalize
     * @param penaltyAmount Amount of reputation to deduct
     * @param reason Reason for the penalty
     * @return success Whether penalty was applied successfully
     */
    function penalizeEngine(
        address engineAddress,
        uint256 penaltyAmount,
        string calldata reason
    ) external returns (bool success);

    /**
     * @notice Apply reputation decay for inactive engines
     * @param engineAddress Address of the engine
     * @return newReputation Updated reputation after decay
     */
    function applyReputationDecay(
        address engineAddress
    ) external returns (uint256 newReputation);

    // ============ View Functions ============

    /**
     * @notice Get current reputation score of an engine
     * @param engineAddress Address of the engine
     * @return reputation Current reputation score
     */
    function getReputation(
        address engineAddress
    ) external view returns (uint256 reputation);

    /**
     * @notice Get detailed information about an engine
     * @param engineAddress Address of the engine
     * @return engineInfo Complete engine information
     */
    // function getEngineInfo(address engineAddress) 
    //     external 
    //     view 
    //     override
    //     returns (EngineInfo memory) 
    // {
    //     AnalystProfile storage profile = analysts[engineAddress];
    //     return EngineInfo({
    //         isRegistered: profile.isActive,
    //         engineType: uint8(profile.category),
    //         reputation: profile.reputation,
    //         totalAnalyses: profile.totalSubmissions,
    //         correctAnalyses: profile.correctPredictions,
    //         lastActivityTimestamp: profile.lastActiveTimestamp,
    //         registrationTimestamp: profile.registrationTimestamp,
    //         isActive: profile.isActive
    //     });
    // }

    /**
     * @notice Get accuracy rate of an engine
     * @param engineAddress Address of the engine
     * @return accuracyRate Accuracy as a percentage (0-10000, where 10000 = 100%)
     */
    function getAccuracyRate(
        address engineAddress
    ) external view returns (uint256 accuracyRate);

    /**
     * @notice Check if an engine is eligible to participate in bounties
     * @param engineAddress Address of the engine
     * @return eligible Whether the engine meets minimum reputation requirements
     */
    function isEligibleEngine(
        address engineAddress
    ) external view returns (bool eligible);

    /**
     * @notice Get reputation history for an engine
     * @param engineAddress Address of the engine
     * @param limit Maximum number of records to return
     * @return records Array of reputation change records
     */
    function getReputationHistory(
        address engineAddress,
        uint256 limit
    ) external view returns (ReputationRecord[] memory records);

    /**
     * @notice Get list of top engines by reputation
     * @param limit Maximum number of engines to return
     * @return engines Array of engine addresses sorted by reputation
     * @return reputations Corresponding reputation scores
     */
    function getTopEngines(
        uint256 limit
    ) external view returns (
        address[] memory engines,
        uint256[] memory reputations
    );

    /**
     * @notice Calculate required stake amount based on reputation
     * @param engineAddress Address of the engine
     * @param baseStake Base stake amount for the bounty
     * @return requiredStake Adjusted stake amount based on reputation
     */
    function calculateRequiredStake(
        address engineAddress,
        uint256 baseStake
    ) external view returns (uint256 requiredStake);

    // ============ Configuration ============

    /**
     * @notice Get minimum reputation required to participate
     * @return minReputation Minimum reputation threshold
     */
    function getMinimumReputation() external view returns (uint256 minReputation);

    /**
     * @notice Get reputation decay parameters
     * @return decayRate Rate of decay per time period
     * @return decayPeriod Time period for decay application
     */
    function getDecayParameters() external view returns (
        uint256 decayRate,
        uint256 decayPeriod
    );

    /**
     * @notice Get reputation multipliers for different engine types
     * @param engineType Type of engine (0: Human, 1: Automated)
     * @return multiplier Reputation multiplier for rewards/penalties
     */
    function getEngineMultiplier(
        uint8 engineType
    ) external view returns (uint256 multiplier);
}

contracts/upgradeable/BountyManagerV2.so.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "../Interfaces/IBountyManager.sol";
import "../Interfaces/IReputationSystem.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title BountyManagerV2
 * @dev Upgradeable version of BountyManager with enhanced features
 * @notice V2 improvements: Better consensus mechanism, dispute resolution, multi-sig support
 */
contract BountyManagerV2 is
    Initializable,
    UUPSUpgradeable,
    AccessControlUpgradeable,
    ReentrancyGuardUpgradeable,
    PausableUpgradeable
{
    // ============ ROLES ============

    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    // ============ STATE VARIABLES ============

    IERC20 public threatToken;
    IReputationSystem public reputationSystem;

    uint256 public bountyCounter;
    uint256 public constant MIN_STAKE_AMOUNT = 10 * 10**18;
    uint256 public constant ANALYSIS_TIMEOUT = 24 hours;
    uint256 public constant CONSENSUS_THRESHOLD = 66;
    uint256 public constant PLATFORM_FEE_PERCENT = 5;
    uint256 public constant MIN_ANALYSES_TO_RESOLVE = 5;

    // V2 Additions
    uint256 public constant DISPUTE_PERIOD = 48 hours;
    uint256 public constant MIN_DISPUTE_STAKE = 50 * 10**18;
    uint256 public disputeCounter;

    address public feeCollector;

    // ============ ENUMS ============

    enum BountyStatus {
        Active,
        Resolved,
        Disputed,
        Cancelled
    }

    enum ThreatVerdict {
        Pending,
        Malicious,
        Benign
    }

    enum ArtifactType {
        File,
        URL,
        Hash,
        Domain,
        IP
    }

    enum DisputeStatus {
        Active,
        Resolved,
        Rejected
    }

    // ============ STRUCTS ============

    struct Bounty {
        uint256 id;
        address creator;
        string artifactHash;
        ArtifactType artifactType;
        uint256 rewardAmount;
        uint256 deadline;
        string description;
        BountyStatus status;
        ThreatVerdict consensusVerdict;
        uint256 totalStaked;
        uint256 analysisCount;
        uint256 createdAt;
    }

    struct Analysis {
        address analyst;
        ThreatVerdict verdict;
        uint256 confidence;
        uint256 stakeAmount;
        string analysisHash;
        uint256 submittedAt;
        bool rewarded;
    }

    // V2: Dispute mechanism
    struct Dispute {
        uint256 id;
        uint256 bountyId;
        address disputer;
        string reason;
        uint256 stakeAmount;
        DisputeStatus status;
        uint256 createdAt;
        uint256 resolvedAt;
        address resolver;
    }

    // ============ MAPPINGS ============

    mapping(uint256 => Bounty) public bounties;
    mapping(uint256 => mapping(address => Analysis)) public analyses;
    mapping(uint256 => address[]) public bountyAnalysts;
    mapping(address => uint256[]) public userBounties;
    mapping(uint256 => mapping(address => uint256)) public analystSubmissionIds;

    // V2 Additions
    mapping(uint256 => Dispute[]) public bountyDisputes;
    mapping(uint256 => bool) public isDisputed;
    mapping(address => bool) public trustedResolvers;

    // ============ EVENTS ============

    event BountyCreated(
        uint256 indexed bountyId,
        address indexed creator,
        string artifactHash,
        uint256 reward,
        uint256 deadline
    );

    event AnalysisSubmitted(
        uint256 indexed bountyId,
        address indexed analyst,
        ThreatVerdict verdict,
        uint256 stakeAmount,
        string analysisHash
    );

    event BountyResolved(
        uint256 indexed bountyId,
        ThreatVerdict consensusVerdict,
        uint256 totalReward,
        uint256 winnerCount
    );

    event StakeSlashed(
        uint256 indexed bountyId,
        address indexed analyst,
        uint256 slashedAmount
    );

    event RewardDistributed(
        uint256 indexed bountyId,
        address indexed analyst,
        uint256 rewardAmount
    );

    // V2 Events
    event DisputeCreated(
        uint256 indexed disputeId,
        uint256 indexed bountyId,
        address indexed disputer,
        string reason
    );

    event DisputeResolved(
        uint256 indexed disputeId,
        uint256 indexed bountyId,
        DisputeStatus status,
        address resolver
    );

    event TrustedResolverAdded(address indexed resolver);
    event TrustedResolverRemoved(address indexed resolver);

    // ============ MODIFIERS ============

    modifier validBounty(uint256 bountyId) {
        require(bountyId > 0 && bountyId <= bountyCounter, "Invalid bounty ID");
        _;
    }

    modifier bountyActive(uint256 bountyId) {
        require(bounties[bountyId].status == BountyStatus.Active, "Bounty not active");
        require(block.timestamp <= bounties[bountyId].deadline, "Bounty expired");
        _;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    // ============ INITIALIZER ============

    /**
     * @dev Initialize the contract (replaces constructor for upgradeable)
     */
    function initialize(
        address _threatToken,
        address _reputationSystem,
        address _feeCollector
    ) public initializer {
        require(_threatToken != address(0), "Invalid token address");
        require(_reputationSystem != address(0), "Invalid reputation system");
        require(_feeCollector != address(0), "Invalid fee collector");

        __UUPSUpgradeable_init();
        __AccessControl_init();
        __ReentrancyGuard_init();
        __Pausable_init();

        threatToken = IERC20(_threatToken);
        reputationSystem = IReputationSystem(_reputationSystem);
        feeCollector = _feeCollector;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(UPGRADER_ROLE, msg.sender);
        _grantRole(PAUSER_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
    }

    // ============ BOUNTY FUNCTIONS ============

    /**
     * @dev Create a new bounty (same as V1)
     */
    function createBounty(
        string memory artifactHash,
        ArtifactType artifactType,
        uint256 rewardAmount,
        uint256 deadline,
        string memory description
    ) external whenNotPaused returns (uint256) {
        require(bytes(artifactHash).length > 0, "Invalid artifact hash");
        require(rewardAmount > 0, "Reward must be positive");
        require(deadline > block.timestamp + 1 hours, "Deadline too soon");

        require(
            threatToken.transferFrom(msg.sender, address(this), rewardAmount),
            "Token transfer failed"
        );

        bountyCounter++;

        bounties[bountyCounter] = Bounty({
            id: bountyCounter,
            creator: msg.sender,
            artifactHash: artifactHash,
            artifactType: artifactType,
            rewardAmount: rewardAmount,
            deadline: deadline,
            description: description,
            status: BountyStatus.Active,
            consensusVerdict: ThreatVerdict.Pending,
            totalStaked: 0,
            analysisCount: 0,
            createdAt: block.timestamp
        });

        userBounties[msg.sender].push(bountyCounter);

        emit BountyCreated(bountyCounter, msg.sender, artifactHash, rewardAmount, deadline);

        return bountyCounter;
    }

    /**
     * @dev Submit analysis (same as V1)
     */
    function submitAnalysis(
        uint256 bountyId,
        ThreatVerdict verdict,
        uint256 confidence,
        uint256 stakeAmount,
        string memory analysisHash
    ) external validBounty(bountyId) bountyActive(bountyId) whenNotPaused {
        require(verdict != ThreatVerdict.Pending, "Invalid verdict");
        require(confidence > 0 && confidence <= 100, "Invalid confidence");
        require(stakeAmount >= MIN_STAKE_AMOUNT, "Insufficient stake");
        require(analyses[bountyId][msg.sender].analyst == address(0), "Already submitted");

        require(
            reputationSystem.getReputation(msg.sender) >= reputationSystem.getMinimumReputation(),
            "Insufficient reputation"
        );

        require(
            threatToken.transferFrom(msg.sender, address(this), stakeAmount),
            "Stake transfer failed"
        );

        analyses[bountyId][msg.sender] = Analysis({
            analyst: msg.sender,
            verdict: verdict,
            confidence: confidence,
            stakeAmount: stakeAmount,
            analysisHash: analysisHash,
            submittedAt: block.timestamp,
            rewarded: false
        });

        bountyAnalysts[bountyId].push(msg.sender);
        bounties[bountyId].totalStaked += stakeAmount;
        bounties[bountyId].analysisCount++;

        // TODO: recordSubmission is not part of IReputationSystem interface
        // Reputation updates are handled in resolveBounty via updateReputationForAnalysis
        // uint256 submissionId = reputationSystem.recordSubmission(
        //     msg.sender,
        //     bountyId,
        //     (verdict == ThreatVerdict.Malicious),
        //     stakeAmount,
        //     confidence
        // );
        // analystSubmissionIds[bountyId][msg.sender] = submissionId;

        emit AnalysisSubmitted(bountyId, msg.sender, verdict, stakeAmount, analysisHash);

        _checkAndResolveBounty(bountyId);
    }

    // ============ V2: DISPUTE FUNCTIONS ============

    /**
     * @dev Create a dispute for a resolved bounty
     * @param bountyId ID of the bounty to dispute
     * @param reason Reason for the dispute
     */
    function createDispute(
        uint256 bountyId,
        string memory reason
    ) external validBounty(bountyId) nonReentrant whenNotPaused {
        Bounty storage bounty = bounties[bountyId];
        require(bounty.status == BountyStatus.Resolved, "Bounty not resolved");
        require(
            block.timestamp <= bounty.deadline + DISPUTE_PERIOD,
            "Dispute period ended"
        );
        require(!isDisputed[bountyId], "Already disputed");
        require(bytes(reason).length > 0, "Reason required");

        // Require dispute stake
        require(
            threatToken.transferFrom(msg.sender, address(this), MIN_DISPUTE_STAKE),
            "Dispute stake transfer failed"
        );

        disputeCounter++;

        Dispute memory newDispute = Dispute({
            id: disputeCounter,
            bountyId: bountyId,
            disputer: msg.sender,
            reason: reason,
            stakeAmount: MIN_DISPUTE_STAKE,
            status: DisputeStatus.Active,
            createdAt: block.timestamp,
            resolvedAt: 0,
            resolver: address(0)
        });

        bountyDisputes[bountyId].push(newDispute);
        isDisputed[bountyId] = true;
        bounty.status = BountyStatus.Disputed;

        emit DisputeCreated(disputeCounter, bountyId, msg.sender, reason);
    }

    /**
     * @dev Resolve a dispute (trusted resolvers only)
     * @param bountyId ID of the disputed bounty
     * @param disputeIndex Index of the dispute in the array
     * @param accept Whether to accept the dispute
     */
    function resolveDispute(
        uint256 bountyId,
        uint256 disputeIndex,
        bool accept
    ) external validBounty(bountyId) nonReentrant {
        require(
            trustedResolvers[msg.sender] || hasRole(OPERATOR_ROLE, msg.sender),
            "Not authorized"
        );
        require(isDisputed[bountyId], "Bounty not disputed");
        require(disputeIndex < bountyDisputes[bountyId].length, "Invalid dispute index");

        Dispute storage dispute = bountyDisputes[bountyId][disputeIndex];
        require(dispute.status == DisputeStatus.Active, "Dispute not active");

        if (accept) {
            dispute.status = DisputeStatus.Resolved;
            // Return dispute stake plus bonus
            threatToken.transfer(dispute.disputer, dispute.stakeAmount + (dispute.stakeAmount / 2));

            // Re-open bounty for re-resolution or manual handling
            bounties[bountyId].status = BountyStatus.Active;
        } else {
            dispute.status = DisputeStatus.Rejected;
            // Slash dispute stake
            threatToken.transfer(feeCollector, dispute.stakeAmount);

            // Restore resolved status
            bounties[bountyId].status = BountyStatus.Resolved;
        }

        dispute.resolvedAt = block.timestamp;
        dispute.resolver = msg.sender;
        isDisputed[bountyId] = false;

        emit DisputeResolved(dispute.id, bountyId, dispute.status, msg.sender);
    }

    // ============ INTERNAL FUNCTIONS ============

    function _checkAndResolveBounty(uint256 bountyId) internal {
        Bounty storage bounty = bounties[bountyId];

        if (bounty.analysisCount >= MIN_ANALYSES_TO_RESOLVE * 2 || block.timestamp > bounty.deadline) {
            _resolveBountyInternal(bountyId);
        }
    }

    function _resolveBountyInternal(uint256 bountyId) internal {
        Bounty storage bounty = bounties[bountyId];
        address[] storage analysts = bountyAnalysts[bountyId];

        if (analysts.length == 0) {
            bounty.status = BountyStatus.Cancelled;
            threatToken.transfer(bounty.creator, bounty.rewardAmount);
            return;
        }

        (ThreatVerdict consensus, uint256 consensusCount) = _calculateConsensus(bountyId);

        bounty.consensusVerdict = consensus;
        bounty.status = BountyStatus.Resolved;

        // Update reputation for all analysts based on their analysis accuracy
        for (uint256 i = 0; i < analysts.length; i++) {
            address analyst = analysts[i];
            Analysis storage analysis = analyses[bountyId][analyst];

            // Check if analyst's verdict matches consensus
            bool wasCorrect = (analysis.verdict == consensus);

            // Update reputation in reputation system
            reputationSystem.updateReputationForAnalysis(
                analyst,
                bountyId,
                wasCorrect,
                analysis.stakeAmount
            );
        }

        _distributeRewards(bountyId, consensus, consensusCount);

        emit BountyResolved(bountyId, consensus, bounty.rewardAmount, consensusCount);
    }

    function _calculateConsensus(uint256 bountyId)
        internal
        view
        returns (ThreatVerdict consensus, uint256 consensusCount)
    {
        address[] storage analysts = bountyAnalysts[bountyId];
        uint256 maliciousCount = 0;
        uint256 benignCount = 0;
        uint256 totalWeight = 0;

        for (uint256 i = 0; i < analysts.length; i++) {
            Analysis storage analysis = analyses[bountyId][analysts[i]];
            uint256 weight = analysis.stakeAmount * analysis.confidence / 100;
            totalWeight += weight;

            if (analysis.verdict == ThreatVerdict.Malicious) {
                maliciousCount += weight;
            } else if (analysis.verdict == ThreatVerdict.Benign) {
                benignCount += weight;
            }
        }

        if (totalWeight == 0) return (ThreatVerdict.Pending, 0);

        uint256 maliciousPercent = (maliciousCount * 100) / totalWeight;

        if (maliciousPercent >= CONSENSUS_THRESHOLD) {
            consensus = ThreatVerdict.Malicious;
            consensusCount = _countCorrectAnalyses(bountyId, ThreatVerdict.Malicious);
        } else if ((benignCount * 100) / totalWeight >= CONSENSUS_THRESHOLD) {
            consensus = ThreatVerdict.Benign;
            consensusCount = _countCorrectAnalyses(bountyId, ThreatVerdict.Benign);
        } else {
            consensus = ThreatVerdict.Pending;
            consensusCount = 0;
        }
    }

    function _countCorrectAnalyses(uint256 bountyId, ThreatVerdict consensus)
        internal
        view
        returns (uint256 count)
    {
        address[] storage analysts = bountyAnalysts[bountyId];
        for (uint256 i = 0; i < analysts.length; i++) {
            if (analyses[bountyId][analysts[i]].verdict == consensus) {
                count++;
            }
        }
    }

    function _distributeRewards(
        uint256 bountyId,
        ThreatVerdict consensus,
        uint256 winnerCount
    ) internal {
        Bounty storage bounty = bounties[bountyId];
        address[] storage analysts = bountyAnalysts[bountyId];

        uint256 platformFee = (bounty.rewardAmount * PLATFORM_FEE_PERCENT) / 100;
        uint256 rewardPool = bounty.rewardAmount - platformFee;

        if (consensus == ThreatVerdict.Pending || winnerCount == 0) {
            uint256 refundAmount = bounty.rewardAmount - platformFee;
            threatToken.transfer(feeCollector, platformFee);
            threatToken.transfer(bounty.creator, refundAmount);

            for (uint256 i = 0; i < analysts.length; i++) {
                Analysis storage analysis = analyses[bountyId][analysts[i]];
                threatToken.transfer(analysts[i], analysis.stakeAmount);
            }
            return;
        }

        uint256 slashedAmount = _processSlashing(bountyId, consensus);
        rewardPool += slashedAmount;

        uint256 individualReward = rewardPool / winnerCount;

        for (uint256 i = 0; i < analysts.length; i++) {
            address analyst = analysts[i];
            Analysis storage analysis = analyses[bountyId][analyst];

            if (analysis.verdict == consensus && !analysis.rewarded) {
                analysis.rewarded = true;
                uint256 totalPayout = analysis.stakeAmount + individualReward;
                threatToken.transfer(analyst, totalPayout);

                emit RewardDistributed(bountyId, analyst, individualReward);
            }
        }

        threatToken.transfer(feeCollector, platformFee);
    }

    function _processSlashing(uint256 bountyId, ThreatVerdict consensus)
        internal
        returns (uint256 totalSlashed)
    {
        address[] storage analysts = bountyAnalysts[bountyId];

        for (uint256 i = 0; i < analysts.length; i++) {
            Analysis storage analysis = analyses[bountyId][analysts[i]];

            if (analysis.verdict != consensus) {
                totalSlashed += analysis.stakeAmount;
                emit StakeSlashed(bountyId, analysts[i], analysis.stakeAmount);
            }
        }
    }

    // ============ ADMIN FUNCTIONS ============

    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    function setFeeCollector(address _feeCollector) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_feeCollector != address(0), "Invalid fee collector");
        feeCollector = _feeCollector;
    }

    function addTrustedResolver(address resolver) external onlyRole(OPERATOR_ROLE) {
        require(resolver != address(0), "Invalid address");
        trustedResolvers[resolver] = true;
        emit TrustedResolverAdded(resolver);
    }

    function removeTrustedResolver(address resolver) external onlyRole(OPERATOR_ROLE) {
        trustedResolvers[resolver] = false;
        emit TrustedResolverRemoved(resolver);
    }

    // ============ VIEW FUNCTIONS ============

    function getBounty(uint256 bountyId) external view validBounty(bountyId) returns (Bounty memory) {
        return bounties[bountyId];
    }

    function getAnalysis(uint256 bountyId, address analyst)
        external
        view
        validBounty(bountyId)
        returns (Analysis memory)
    {
        return analyses[bountyId][analyst];
    }

    function getBountyAnalysts(uint256 bountyId)
        external
        view
        validBounty(bountyId)
        returns (address[] memory)
    {
        return bountyAnalysts[bountyId];
    }

    function getBountyDisputes(uint256 bountyId)
        external
        view
        validBounty(bountyId)
        returns (Dispute[] memory)
    {
        return bountyDisputes[bountyId];
    }

    // ============ UPGRADE AUTHORIZATION ============

    function _authorizeUpgrade(address newImplementation)
        internal
        override
        onlyRole(UPGRADER_ROLE)
    {}

    /**
     * @dev Get version
     */
    function version() external pure returns (string memory) {
        return "2.0.0";
    }
}

